import 'package:flutter/material.dart';
import 'package:shared_preferences/shared_preferences.dart';

class AuthenticationManager extends ChangeNotifier {
  String _accessToken;
  String _refreshToken;
  Map<String, String> _userData;

  String get accessToken => _accessToken;
  String get refreshToken => _refreshToken;
  Map<String, String> get userData => _userData;

  Future<void> init() async {
    SharedPreferences prefs = await SharedPreferences.getInstance();
    _accessToken = prefs.getString('accessToken') ?? '';
    _refreshToken = prefs.getString('refreshToken') ?? '';
    _userData = Map.from(prefs.get('userData') ?? {});
    notifyListeners();
  }

  Future<void> login(String email, String password) async {
    // Perform login logic here
    // ...

    // Save auth tokens and user data
    SharedPreferences prefs = await SharedPreferences.getInstance();
    await prefs.setString('accessToken', _accessToken);
    await prefs.setString('refreshToken', _refreshToken);
    await prefs.setString('userData', jsonEncode(_userData));
    notifyListeners();
  }

  Future<void> logout() async {
    SharedPreferences prefs = await SharedPreferences.getInstance();
    await prefs.remove('accessToken');
    await prefs.remove('refreshToken');
    await prefs.remove('userData');
    notifyListeners();
  }
}